INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", "", 21, "", 0, 0, "vo_minigame_1013_top_talk_6_001", 6010, 6, "vo_minigame_1013", "");
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (0.8, 0, 11, 0, 6, 1, "マコトさん？\nどうかしましたか？\n何やら不穏な気配を\n感じ取ったのですが", 6011, 6, 129911, 0);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", "", 91, "", "", "", "", 6012, 6, 0, "");
