INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", "", 3, 0.2, 0, "drama_talk_surprise_loop_shy", "drama_talk_surprise_in_shy", 6014, 6, 129811, 1);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", "", 21, "", 0, 0, "vo_minigame_1013_top_talk_6_002", 6015, 6, "vo_minigame_1013", "");
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (0.3, 0, 11, 0, 9, 1, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 6016, 6, 129811, 0);
