INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (0.3, 0, 11, 0, 6, 1, "私の班のみなさんも\n変わらず訓練に励んで\nいるようですわね\n殊勝なことです", 7006, 7, 129911, 0);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", "", 91, "", "", "", "", 7007, 7, 0, "");
